$(document).ready(function(){$(".header__form-trigger-btn").on("click",function(e){e.preventDefault(),$(".header__form-holder").addClass("header__form-holder--active")}),$(".btn-play-video").on("click",function(e){e.preventDefault(),$(".video-holder").addClass("active")})});var player;function onYouTubePlayerAPIReady(){player=new YT.Player("video",{events:{onReady:onPlayerReady}})}function onPlayerReady(e){document.getElementById("play-button").addEventListener("click",function(){player.playVideo()})}var tag=document.createElement("script");tag.src="//www.youtube.com/player_api";var firstScriptTag=document.getElementsByTagName("script")[0];firstScriptTag.parentNode.insertBefore(tag,firstScriptTag);